struct Container<T> {
    inner: T,
}

impl<T> Container<T> {
    fn new(inner: T) -> Self {
        Self { inner }
    }
}

fn main() {
    let mut data = vec![Container::new(1), Container::new(2)];
    for item in &mut data {
        println!("{}", item.inner);
    }
}

